.ai-tool__ref-info {
  display: flex;
  flex-direction: column;
  gap: 0.3rem;
  min-width: 0;
}

.ai-tool__ref-name {
  font-size: 0.8rem;
  color: var(--text-primary, #fff);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  max-width: 160px;
}

.ai-tool__ref-remove {
  background: none;
  border: none;
  color: var(--text-secondary, rgba(255,255,255,0.45));
  font-size: 0.75rem;
  cursor: pointer;
  padding: 0;
  text-align: left;
}

.ai-tool__ref-remove:hover {
  color: #ef4444;
}

/* Templates */
.ai-tool__template-row {

toolUseResult.originalFile:
.ai-tool {
  display: flex;
  flex-direction: column;
  gap: 1.5rem;
  height: 100%;
}

.ai-tool__header {
  padding-bottom: 1.25rem;
  border-bottom: 1px solid var(--border-color);
}

.ai-tool__title-row {
  display: flex;
  align-items: flex-start;
  gap: 1rem;
}

.ai-tool__icon {
  font-size: 2rem;
  line-height: 1;
  flex-shrink: 0;
}

.ai-tool__title {
  font-size: 1.4rem;
  color: var(--text-primary);
  margin-bottom: 0.25rem;
}

.ai-tool__description {
  font-size: 0.9rem;
  color: var(--text-muted);
}

/* Business context block */
.ai-tool__biz-context {
  background: rgba(99, 102, 241, 0.06);
  border: 1px solid rgba(99, 102, 241, 0.18);
  border-radius: var(--border-radius);
  padding: 1rem 1.1rem 0.5rem;
  margin-bottom: 1.25rem;
}

.ai-tool__biz-context-label {
  display: block;
  font-size: 0.75rem;
  font-weight: 600;
  letter-spacing: 0.05em;
  text-transform: uppercase;
  color: var(--accent-primary);
  margin-bottom: 0.75rem;
}

/* Upgrade notice */
.ai-tool__upgrade {
  display: flex;
  align-items: center;
  gap: 1rem;
  padding: 1rem 1.25rem;
  background: rgba(99,102,241,0.08);
  border: 1px solid rgba(99,102,241,0.2);
  border-radius: var(--border-radius);
}

.ai-tool__upgrade-icon {
  font-size: 1.5rem;
  flex-shrink: 0;
}

.ai-tool__upgrade > div {
  flex: 1;
}

.ai-tool__upgrade strong {
  display: block;
  color: var(--text-primary);
  font-size: 0.9rem;
  margin-bottom: 0.2rem;
}

.ai-tool__upgrade p {
  font-size: 0.82rem;
  color: var(--text-muted);
}

/* Layout */
.ai-tool__layout {
  display: grid;
  grid-template-columns: 380px 1fr;
  grid-template-rows: 1fr;   /* row height = available space, not content height */
  gap: 1.5rem;
  flex: 1;
  min-height: 0;
}

.ai-tool__panel {
  background: var(--bg-card);
  border: 1px solid var(--border-color);
  border-radius: var(--border-radius-lg);
  padding: 1.5rem;
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  min-height: 0;  /* allow flex children to shrink and scroll */
  overflow: hidden;
}

.ai-tool__panel-title {
  font-size: 0.9rem;
  font-weight: 700;
  color: var(--text-secondary);
  letter-spacing: 0.03em;
  margin-bottom: 0.75rem;
}

/* Input panel */
.ai-tool__input-panel {
  overflow-y: auto;
}

.ai-tool__actions {
  display: flex;
  gap: 0.75rem;
  align-items: center;
  margin-top: 0.5rem;
}

.required-mark {
  color: #f87171;
  margin-left: 2px;
}

/* Output panel */
.ai-tool__output-panel {
  overflow: hidden;
}

.ai-tool__output-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 1rem;
  flex-shrink: 0;
}

.ai-tool__streaming {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  color: var(--color-primary-light);
  font-size: 0.9rem;
}

.ai-tool__streaming-dot {
  width: 8px;
  height: 8px;
  background: var(--color-primary);
  border-radius: 50%;
  animation: pulse-dot 1s ease-in-out infinite;
}

@keyframes pulse-dot {
  0%, 100% { transform: scale(1); opacity: 1; }
  50% { transform: scale(1.5); opacity: 0.6; }
}

.ai-tool__output-controls {
  display: flex;
  align-items: center;
  gap: 0.75rem;
}

.ai-tool__word-count {
  font-size: 0.78rem;
  color: var(--text-muted);
}

.ai-tool__output-body {
  flex: 1;
  overflow-y: auto;
  min-height: 0;
}

/* Placeholder */
.ai-tool__output-placeholder {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  text-align: center;
  gap: 1rem;
  height: 100%;
  min-height: 300px;
}

.ai-tool__placeholder-icon {
  font-size: 3rem;
  opacity: 0.4;
}

.ai-tool__output-placeholder p {
  max-width: 300px;
  font-size: 0.9rem;
  color: var(--text-muted);
}

.ai-tool__output-placeholder strong {
  color: var(--text-secondary);
}

.ai-tool__placeholder-features {
  display: flex;
  gap: 0.75rem;
  flex-wrap: wrap;
  justify-content: center;
}

.ai-tool__placeholder-features span {
  font-size: 0.78rem;
  color: var(--text-muted);
  background: var(--bg-surface-2);
  padding: 0.3rem 0.75rem;
  border-radius: 100px;
  border: 1px solid var(--border-color);
}

/* Output content */
.ai-tool__output-content {
  font-size: 0.9rem;
  line-height: 1.75;
  padding-right: 0.5rem;
}

.ai-tool__cursor {
  display: inline-block;
  animation: blink 1s ease infinite;
  color: var(--color-primary);
  margin-left: 2px;
}

@keyframes blink {
  0%, 100% { opacity: 1; }
  50% { opacity: 0; }
}

/* Empty state */
.ai-tool__empty {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  text-align: center;
  gap: 1rem;
  height: 100%;
  min-height: 400px;
}

.ai-tool__empty-icon { font-size: 3rem; }
.ai-tool__empty h3 { font-size: 1.25rem; }
.ai-tool__empty p { color: var(--text-muted); font-size: 0.9rem; }

/* ── Markdown output ── */
.markdown-output h1,
.markdown-output h2,
.markdown-output h3,
.markdown-output h4 {
  color: var(--text-primary);
  margin: 1.25rem 0 0.5rem;
  line-height: 1.3;
}
.markdown-output h1 { font-size: 1.3rem; }
.markdown-output h2 { font-size: 1.1rem; }
.markdown-output h3 { font-size: 1rem; }
.markdown-output p { margin: 0.5rem 0; }
.markdown-output ul,
.markdown-output ol { padding-left: 1.4rem; margin: 0.5rem 0; }
.markdown-output li { margin: 0.2rem 0; }
.markdown-output strong { color: var(--text-primary); }
.markdown-output code {
  background: rgba(99,102,241,0.12);
  color: var(--color-primary-light);
  padding: 0.15em 0.4em;
  border-radius: 4px;
  font-size: 0.85em;
}
.markdown-output pre {
  background: var(--bg-surface-2);
  border: 1px solid var(--border-color);
  border-radius: var(--border-radius);
  padding: 1rem;
  overflow-x: auto;
  margin: 0.75rem 0;
}
.markdown-output pre code { background: none; padding: 0; font-size: 0.85rem; }
.markdown-output blockquote {
  border-left: 3px solid var(--color-primary);
  padding-left: 1rem;
  color: var(--text-muted);
  margin: 0.75rem 0;
}
.markdown-output hr {
  border: none;
  border-top: 1px solid var(--border-color);
  margin: 1rem 0;
}

/* ── GFM Tables ── */
.markdown-output table {
  width: 100%;
  border-collapse: collapse;
  margin: 1rem 0;
  font-size: 0.855rem;
  display: block;
  overflow-x: auto;
}
.markdown-output thead tr { background: rgba(99,102,241,0.12); }
.markdown-output th {
  padding: 0.6rem 0.9rem;
  text-align: left;
  font-weight: 700;
  color: var(--text-primary);
  border: 1px solid var(--border-color);
  white-space: nowrap;
}
.markdown-output td {
  padding: 0.55rem 0.9rem;
  border: 1px solid var(--border-color);
  color: var(--text-secondary);
  vertical-align: top;
}
.markdown-output tbody tr:nth-child(even) { background: rgba(255,255,255,0.02); }
.markdown-output tbody tr:hover { background: rgba(99,102,241,0.06); }

/* ── Query History ── */
.ai-tool__history {
  border: 1px solid var(--border-color);
  border-radius: var(--border-radius-lg);
  overflow: hidden;
  background: var(--bg-card);
}

.ai-tool__history-toggle {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  width: 100%;
  padding: 0.75rem 1rem;
  background: none;
  border: none;
  color: var(--text-secondary);
  font-size: 0.85rem;
  font-weight: 600;
  cursor: pointer;
  font-family: var(--font-sans);
  text-align: left;
  transition: background var(--transition-fast);
}

.ai-tool__history-toggle:hover {
  background: rgba(255, 255, 255, 0.04);
  color: var(--text-primary);
}

.ai-tool__history-arrow {
  margin-left: auto;
  font-size: 0.7rem;
  color: var(--text-muted);
  transition: transform 0.2s ease;
  display: inline-block;
}

.ai-tool__history-arrow.open {
  transform: rotate(180deg);
}

.ai-tool__history-list {
  display: flex;
  flex-direction: column;
  border-top: 1px solid var(--border-color);
  max-height: 280px;
  overflow-y: auto;
}

.ai-tool__history-item {
  display: flex;
  align-items: baseline;
  gap: 0.75rem;
  width: 100%;
  padding: 0.6rem 1rem;
  background: none;
  border: none;
  border-bottom: 1px solid var(--border-color);
  cursor: pointer;
  font-family: var(--font-sans);
  text-align: left;
  transition: background var(--transition-fast);
}

.ai-tool__history-item:last-child {
  border-bottom: none;
}

.ai-tool__history-item:hover {
  background: rgba(99, 102, 241, 0.06);
}

.ai-tool__history-time {
  font-size: 0.72rem;
  color: var(--color-primary-light);
  white-space: nowrap;
  flex-shrink: 0;
  font-weight: 600;
}

.ai-tool__history-preview {
  font-size: 0.82rem;
  color: var(--text-muted);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

@media (max-width: 1100px) {
  .ai-tool__layout {
    grid-template-columns: 1fr;
    grid-template-rows: auto 1fr;
  }
  .ai-tool__output-panel { min-height: 400px; }
}

/* ========== IMAGE GENERATION BLOCK ========== */
.ai-tool__image-block {
  margin-top: 2rem;
  padding-top: 1.5rem;
  border-top: 1px solid var(--border-color);
  display: flex;
  flex-direction: column;
  gap: 1rem;
}

.ai-tool__image-divider {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  font-size: 0.85rem;
  font-weight: 700;
  color: var(--text-secondary);
  letter-spacing: 0.02em;
}

.ai-tool__image-btn {
  align-self: flex-start;
}

.ai-tool__image-result {
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
  align-items: flex-start;
}

.ai-tool__generated-img {
  width: 100%;
  max-width: 480px;
  border-radius: 16px;
  border: 1px solid var(--border-color);
  box-shadow: 0 8px 32px rgba(0,0,0,0.25);
}

.ai-tool__image-download {
  align-self: flex-start;
}

/* ── Image loading spinner ── */
.ai-tool__image-loading {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 1rem;
  padding: 3rem;
  color: var(--text-muted);
  font-size: 0.9rem;
}

.ai-tool__image-spinner {
  width: 40px;
  height: 40px;
  border: 3px solid var(--border-color);
  border-top-color: #6366f1;
  border-radius: 50%;
  animation: spin 0.8s linear infinite;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

/* ── imageOnly full result ── */
.ai-tool__image-result--full {
  width: 100%;
}

.ai-tool__image-result--full .ai-tool__generated-img {
  max-width: 100%;
  width: 100%;
  border-radius: 16px;
}

.ai-tool__image-caption {
  font-size: 0.8rem;
  color: var(--text-muted);
  margin: 0.5rem 0;
}

.ai-tool__image-actions {
  display: flex;
  gap: 0.75rem;
  flex-wrap: wrap;
}

/* Templates */
.ai-tool__template-row {
  display: flex;
  align-items: stretch;
}
.ai-tool__template-item {
  flex: 1;
  text-align: left;
}
.ai-tool__template-delete {
  background: none;
  border: none;
  border-left: 1px solid var(--border-color);
  color: var(--text-muted);
  cursor: pointer;
  font-size: 1.1rem;
  padding: 0 0.75rem;
  transition: color 0.15s;
}
.ai-tool__template-delete:hover { color: #ef4444; }

/* Save as template form */
.ai-tool__save-tpl-form {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  flex-wrap: wrap;
}
.ai-tool__save-tpl-input {
  font-size: 0.82rem !important;
  padding: 0.3rem 0.6rem !important;
  height: auto !important;
  min-width: 160px;
}
